    57→static void test_representative_100(void)
    58→{
    59→    /* --- Section 1: Special IEEE 754 values (7) --- */
    60→    emit(0.0);
    61→    emit(-0.0);
    62→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    63→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    64→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    65→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    66→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    67→
    68→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    69→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    70→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    71→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    72→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    73→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    74→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    75→
    76→    /* --- Section 3: Normal boundary values (6) --- */
    77→    emit(DBL_MIN);                  /* smallest normal: 2^-1022 = 0x0010000000000000 */
    78→    emit(-DBL_MIN);
    79→    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    80→    emit(DBL_MAX);                  /* largest normal: 0x7fefffffffffffff */
    81→    emit(-DBL_MAX);
    82→    emit_u(0x7feffffffffffffeULL);  /* one ULP below DBL_MAX */
    83→
    84→    /* --- Section 4: Powers of 2 (14) --- */
    85→    /* frexp(2^n) = (0.5, n+1); mantissa is exactly 0.5 for all powers of 2 */
    86→    emit(0.125);    /* 2^-3 -> mantissa=0.5, exp=-2 */
    87→    emit(-0.125);
    88→    emit(0.25);     /* 2^-2 -> mantissa=0.5, exp=-1 */
    89→    emit(-0.25);
    90→    emit(0.5);      /* 2^-1 -> mantissa=0.5, exp=0 */
    91→    emit(-0.5);
    92→    emit(1.0);      /* 2^0  -> mantissa=0.5, exp=1 */
    93→    emit(-1.0);
    94→    emit(2.0);      /* 2^1  -> mantissa=0.5, exp=2 */
    95→    emit(-2.0);
    96→    emit(4.0);      /* 2^2  -> mantissa=0.5, exp=3 */
    97→    emit(16.0);     /* 2^4  -> mantissa=0.5, exp=5 */
    98→    emit(1024.0);   /* 2^10 -> mantissa=0.5, exp=11 */
    99→    emit_u(0x4330000000000000ULL);  /* 2^52 = 4503599627370496.0 */
   100→
   101→    /* --- Section 5: ULP neighbors of powers of 2 (12) --- */
   102→    /* These test that the exponent increments/decrements correctly at boundaries */
   103→    emit_u(0x3feffffffffffffeULL);  /* 2 ULPs below 1.0 */
   104→    emit_u(0x3fefffffffffffffULL);  /* 1 ULP below 1.0: mantissa just under 1.0 -> exp=0 */
   105→    emit_u(0x3ff0000000000001ULL);  /* 1 ULP above 1.0 */
   106→    emit_u(0x3fffffffffffffffULL);  /* 1 ULP below 2.0: largest value in [1.0, 2.0) */
   107→    emit_u(0x4000000000000001ULL);  /* 1 ULP above 2.0 */
   108→    emit_u(0xbff0000000000001ULL);  /* 1 ULP above -1.0 (toward zero) */
   109→    emit_u(0x3fdffffffffffffeULL);  /* 2 ULPs below 0.5 */
   110→    emit_u(0x3fdfffffffffffffULL);  /* 1 ULP below 0.5 */
   111→    emit_u(0x3fe0000000000001ULL);  /* 1 ULP above 0.5 */
   112→    emit_u(0xc000000000000001ULL);  /* 1 ULP above -2.0 (toward zero) */
   113→    emit_u(0xbfe0000000000001ULL);  /* 1 ULP above -0.5 (toward zero) */
   114→    emit_u(0xbfefffffffffffffULL);  /* 1 ULP above -1.0 (away from zero): just above -1.0 */
   115→
   116→    /* --- Section 6: Mantissa-dense values near [0.5, 1.0) boundary (8) --- */
   117→    /* frexp always returns mantissa in [0.5, 1.0); these stress the mantissa extraction */
   118→    emit_u(0x3fb0000000000000ULL);  /* 0.0625 = 1/16: exponent boundary */
   119→    emit_u(0x3fe4000000000000ULL);  /* 0.625 */
   120→    emit_u(0x3fe8000000000000ULL);  /* 0.75 */
   121→    emit_u(0x3fec000000000000ULL);  /* 0.875 */
   122→    emit_u(0x3ff4000000000000ULL);  /* 1.25: mantissa = 0.625, exp=1 */
   123→    emit_u(0xbfe0000000000000ULL);  /* -0.5 */
   124→    emit_u(0xbfe8000000000000ULL);  /* -0.75 */
   125→    emit_u(0xbfec000000000000ULL);  /* -0.875 */
   126→
   127→    /* --- Section 7: Representative normal values across exponent range (20) --- */
   128→    emit(1.5);
   129→    emit(-1.5);
   130→    emit(3.0);
   131→    emit(-3.0);
   132→    emit(3.5);
   133→    emit(-3.5);
   134→    emit(5.0);
   135→    emit(-5.0);
   136→    emit(7.5);
   137→    emit(-7.5);
   138→    emit(3.14159265358979323846);   /* pi */
   139→    emit(-3.14159265358979323846);
   140→    emit(2.718281828459045235360);  /* e */
   141→    emit(1.4142135623730950488);    /* sqrt(2) */
   142→    emit(100.0);
   143→    emit(-100.0);
   144→    emit(1000.0);
   145→    emit(0.1);
   146→    emit(0.01);
   147→    emit(-0.01);
   148→
   149→    /* --- Section 8: Near-integer fractions (10) --- */
   150→    /* Values like n.5 where the mantissa spans the 0.5 boundary in interesting ways */
   151→    emit(2.5);
   152→    emit(-2.5);
   153→    emit(4.5);
   154→    emit(8.5);
   155→    emit(15.5);
   156→    emit(31.5);
   157→    emit(63.5);
   158→    emit(127.5);
