   162→    /* --- Section 9: Large values and exponent extremes (9) --- */
   163→    emit(1.0e10);
   164→    emit(-1.0e10);
   165→    emit(1.0e100);
   166→    emit(-1.0e100);
   167→    emit(1.0e200);
   168→    emit(-1.0e200);
   169→    emit(1.0e300);
   170→    emit(1.23456789012345e150);
   171→    emit(-9.87654321098765e-150);
   172→
   173→    /* --- Section 10: Small normal values near DBL_MIN (8) --- */
   174→    /* These exercise the subnormal-to-normal boundary and small exponents */
   175→    emit(1.0e-200);
   176→    emit(-1.0e-200);
   177→    emit(1.0e-300);
   178→    emit(-1.0e-300);
   179→    emit_u(0x0020000000000000ULL);  /* 2*DBL_MIN = 2^-1021 */
   180→    emit_u(0x0030000000000000ULL);  /* 3*DBL_MIN (mantissa = 0.75, exp=-1021) */
   181→    emit_u(0x0018000000000000ULL);  /* 1.5*DBL_MIN */
   182→    emit_u(0x8020000000000000ULL);  /* -2*DBL_MIN */
   183→}
