   187→/* 7. Sweep across multiple octaves */
   188→static void test_sweep(void)
   189→{
   190→    double bases[] = { 1.0, 1.5, 2.5, 3.5, 5.0, 7.5 };
   191→    int nbases = sizeof(bases) / sizeof(bases[0]);
   192→    for (int p = -10; p <= 10; p += 2) {
   193→        double scale = (1 << (p / 2));
   194→        if (p & 1) scale *= 1.414213562373095;  /* sqrt(2) */
   195→        for (int i = 0; i < nbases; i++) {
   196→            emit(bases[i] * scale);
   197→        }
   198→    }
   199→}
   200→
   201→/* 8. Sample across exponent range */
   202→static void test_exhaustive_small(void)
   203→{
   204→    static const uint64_t vals[] = {
   205→        0x0000000000000000ULL, /* 0.0 */
   206→        0x3fc0000000000000ULL, /* 0.125 */
   207→        0x3fd0000000000000ULL, /* 0.25 */
   208→        0x3fd8000000000000ULL, /* 0.375 */
   209→        0x3fe0000000000000ULL, /* 0.5 */
   210→        0x3fe4000000000000ULL, /* 0.625 */
   211→        0x3fe8000000000000ULL, /* 0.75 */
   212→        0x3ff0000000000000ULL, /* 1.0 */
   213→    };
   214→    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
   215→        emit_u(vals[i]);
   216→}
   217→
   218→/* 9. Random sweep: 300 evenly spaced inputs */
   219→static void test_random_300(void)
   220→{
   221→    double lo = -100.0;
   222→    double hi =  100.0;
   223→    int n = 300;
   224→    for (int i = 0; i < n; i++) {
   225→        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
   226→        emit(x);
   227→    }
   228→}
